import React from 'react';
import { Link } from 'react-router-dom';

export default function NotFoundPage() {
  return (
    <div style={{ minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center', background: 'var(--bg)', flexDirection: 'column', gap: 16, textAlign: 'center', padding: 24 }}>
      <div style={{ fontFamily: 'Bebas Neue, cursive', fontSize: 120, color: 'var(--border)', lineHeight: 1 }}>404</div>
      <h2 style={{ fontFamily: 'Bebas Neue, cursive', fontSize: 32, letterSpacing: 3, color: 'var(--accent)' }}>PAGE NOT FOUND</h2>
      <p style={{ color: 'var(--muted)', fontFamily: 'DM Mono, monospace', fontSize: 13 }}>The route you're looking for doesn't exist.</p>
      <Link to="/" className="btn btn-primary">→ Back to Dashboard</Link>
    </div>
  );
}
